const cardList = Context.getVariable("card_list").cards
const cardNumbers = cardList.map(card => card.card_number)
// Context.setVariable('card_number_list', cardNumbers)

const maskedCardNumbers = cardNumbers.map(card => {
  return "******" + card.slice(-4);
});
Context.setVariable('card_number_list', maskedCardNumbers);

const activeCardNumbers = cardList.filter(c => c.status === "ACTIVE").map(c => c.card_number)
const maskedActiveCardNumbers = activeCardNumbers.map(card => {
  return "******" + card.slice(-4);
});
Context.setVariable('active_card_number_list', maskedActiveCardNumbers)

const inactiveCardNumbers = cardList.filter(c => c.status === "INACTIVE").map(c => c.card_number)
const maskedInactiveCardNumbers = inactiveCardNumbers.map(card => {
  return "******" + card.slice(-4);
});
Context.setVariable('inactive_card_number_list', maskedInactiveCardNumbers)

const nonactiveCardNumbers = cardList.filter(c => c.status !== "ACTIVE").map(c => c.card_number)
const maskedNonactiveCardNumbers = nonactiveCardNumbers.map(card => {
  return "******" + card.slice(-4);
});
Context.setVariable('not_active_card_number_list', maskedNonactiveCardNumbers)

var contact_id = Context.getVariable("contact_id");
var member_id = Context.getVariable("member_id");

if (contact_id === null || contact_id === undefined || contact_id === '' || isNaN(contact_id)) {
  Context.setVariable("contact_id", member_id);
}
